<div class="page-header"><div><h1>Customer Communications</h1><p class="text-muted">Build targeted email or SMS campaigns and connect delivery to a marketing campaign.</p></div><a class="btn btn-outline-primary" href="/portal/marketing"><i class="fa-solid fa-bullhorn me-1"></i> Marketing dashboard</a></div>
<div class="row g-4"><div class="col-lg-5"><div class="card"><div class="card-body"><h2 class="h5">New campaign</h2><form method="post" action="/portal/communications" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Name</label><input class="form-control" name="name" required></div><div class="col-12"><label class="form-label">Marketing campaign</label><select class="form-select" name="marketing_campaign_id"><option value="">Not linked</option><?php foreach($marketingCampaigns as $mc):?><option value="<?=$mc['id']?>"><?=e($mc['name'])?></option><?php endforeach?></select></div><div class="col-md-6"><label class="form-label">Channel</label><select class="form-select" name="channel"><option value="email">Email</option><option value="sms">SMS</option></select></div><div class="col-md-6"><label class="form-label">Template key</label><input class="form-control" name="template_key" placeholder="seasonal_reminder" required></div><div class="col-12"><label class="form-label">Audience</label><select class="form-select" name="audience_type"><option value="all_customers">All customers</option><option value="recurring_customers">Recurring customers</option><option value="overdue_invoices">Overdue invoices</option><option value="upcoming_jobs">Upcoming jobs</option></select></div><div class="col-12"><label class="form-label">Schedule</label><input type="datetime-local" class="form-control" name="scheduled_at"></div><div class="col-12"><button class="btn btn-primary">Create campaign</button></div></form></div></div></div><div class="col-lg-7"><div class="card"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Campaign</th><th>Channel</th><th>Audience</th><th>Status</th><th>Recipients</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['name'])?></strong><br><small><?=e($r['template_key'])?><?= $r['marketing_campaign_name'] ? ' · '.e($r['marketing_campaign_name']) : '' ?></small></td><td><?=e($r['channel'])?></td><td><?=e(str_replace('_',' ',$r['audience_type']))?></td><td><span class="badge text-bg-secondary"><?=e($r['status'])?></span></td><td><?=number_format((int)$r['recipients'])?></td><td><?php if($r['status']==='draft'):?><form method="post" action="/portal/communications/<?=$r['id']?>/send"><?=csrf_field()?><button class="btn btn-sm btn-outline-primary">Queue</button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div></div></div></div>
